INSERT INTO public.world_encyclopedia
  (id, entity_type, name, parent_id, rumour, common_knowledge, uncommon_knowledge, rare_knowledge, gm_lore, admin_notes, location_subtype, location_scale, map_layer, coord_x, coord_y, sequence_index, sector_count, power_level, water_level, tags, is_published, blob_cx, blob_cy, blob_r, blob_seed, chart_status, sort_order)
VALUES
  ('27fbc1d3-fb98-56e1-8d30-7253c15f9934', 'continent', 'The Impure Fracta', NULL, 'They name it the Impure Fracta — the broken land. They say natural law died here, and the world has been dying slowly ever since.', 'A continent in terminal decline since the Great Dissolution shattered natural law. Reality frays at the edges; the Veil is thin, and fear becomes flesh as Nightmares. It is the seventeenth year of the Age of Nightmares. The land ends in the south at the Wall of the SoA — the holiest place in the world.', 'Six quadrants divide the land, their power and water unevenly spread. The [[Ancient Holy Road|ancient-holy-road]] runs its whole length, a ruined monument no one living could build. Beneath everything runs the Blood of the World — the true currency, older than water, scrap, or faith.', 'The Echo means the land remembers what it was; old stone remembers hardest. Where memory pools, beauty and trauma both repeat. What broke the world is not finished breaking it.', 'Central secret: the relationship between Delirium, the Echo, and the Wall of the SoA. Author to campaign.', 'Continent root entity. All quadrants parent to this.', NULL, 'micro', 'world', 500, 350, NULL, NULL, NULL, NULL, ARRAY['continent']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('48f0400a-f3bd-53c9-8855-1d1a7ac60226', 'quadrant', 'Q1', '27fbc1d3-fb98-56e1-8d30-7253c15f9934', 'The northern apex, where the Road is born. Seven sectors, they say, and the Road splits the top of the world in three.', 'The top quadrant, moderate in power and water. The Ancient Holy Road begins at its middle line, dividing Q1 into three parts. Its sectors are unnamed on most maps.', '', '', '', 'Sector names TBD by GM.', NULL, 'micro', 'continent', 0, 0, NULL, 7, 'moderate', 'moderate', ARRAY['quadrant']::text[], true, 500, 150, 120, 'q1', NULL, NULL),
  ('22766cd4-f472-5320-8da0-e29699596b4b', 'quadrant', 'Q2 — The Revealed Quadrant', '27fbc1d3-fb98-56e1-8d30-7253c15f9934', 'The middle-western reach. Nine sectors. The only quarter of the world anyone has truly mapped.', 'Q2 sits middle-west, nine sectors strong. Two are well known to travellers — the [[Dust Gullets|dust-gullets]] and the [[Pale Reach|pale-reach]] — and the rest are open country, sparsely told.', 'The fall of the [[Blue Leaf Rancho|blue-leaf-rancho]] left a power vacuum across the Gullets that ripples into every neighbouring sector. Water moved the borders here long before armies did.', '', '', 'The fully-authored quadrant. 2 sectors written, 7 placeholder.', NULL, 'micro', 'continent', 0, 0, NULL, 9, 'high', 'moderate', ARRAY['quadrant','revealed']::text[], true, 255, 360, 130, 'q2', NULL, NULL),
  ('79b2f163-e0a7-5749-8167-e5c000a6c74b', 'quadrant', 'Q3', '27fbc1d3-fb98-56e1-8d30-7253c15f9934', 'The jewel of the continent, they say — eleven sectors, the richest land and the best water in a dying world.', 'Centre-middle, eleven sectors. The wealthiest, most powerful, best-watered quarter of the Fracta. The Ancient Holy Road forms its eastern border.', '', '', '', '', NULL, 'micro', 'continent', 0, 0, NULL, 11, 'high', 'abundant', ARRAY['quadrant']::text[], true, 500, 380, 140, 'q3', NULL, NULL),
  ('0295a7a4-1ade-58e8-8109-d526ca99e6b8', 'quadrant', 'Q4', '27fbc1d3-fb98-56e1-8d30-7253c15f9934', '', 'Middle-east, only five sectors — the poorest, driest, most contested quarter, pressed right against the jewel of Q3. A built-in war.', '', '', '', 'The harsh frontier beside the jewel.', NULL, 'micro', 'continent', 0, 0, NULL, 5, 'low', 'scarce', ARRAY['quadrant']::text[], true, 745, 365, 100, 'q4', NULL, NULL),
  ('9e33f75e-5e32-5ea9-888b-9f6d5b5e4a77', 'quadrant', 'Q5', '27fbc1d3-fb98-56e1-8d30-7253c15f9934', '', 'Bottom-west, ten sectors strong.', '', '', '', '', NULL, 'micro', 'continent', 0, 0, NULL, 10, 'high', 'moderate', ARRAY['quadrant']::text[], true, 360, 575, 120, 'q5', NULL, NULL),
  ('5e05b5cc-0e0b-54d9-84d4-07aa20672656', 'quadrant', 'Q6', '27fbc1d3-fb98-56e1-8d30-7253c15f9934', '', 'Bottom-east, eight sectors. The Ancient Holy Road runs down through it to the Wall of the SoA.', '', '', '', '', NULL, 'micro', 'continent', 0, 0, NULL, 8, 'moderate', 'moderate', ARRAY['quadrant']::text[], true, 615, 580, 110, 'q6', NULL, NULL),
  ('c619c671-3d99-5bf6-839c-a7c3d72a24ed', 'sector', 'The Dust Gullets', '22766cd4-f472-5320-8da0-e29699596b4b', 'The Gullets. Mountains full of holes, and the wind screams through them hard enough to strip a man to bone. There''s iron in the rock, they say, and worse than iron under it. The [[Blue Leaf|blue-leaf-rancho]] owned the water there. Owned everything, by owning the water.', 'The Dust Gullets are a frontier of jagged ranges bored through with canyon-sized holes that funnel flesh-scouring windstorms. The ground is rich in ancient iron and copper, valuable to scrap-miners and dangerous to all — dig wrong and you breach a Corruption Vein. Water is the only real currency. The [[Blue Leaf Rancho|blue-leaf-rancho]] held the sector through its monopoly on the one underground river, dammed in the cliffs and routed to their fortress. That fortress, the [[High Aerie|high-aerie]], has recently fallen — and who controls the water now is an open wound.', 'With the Aerie down, the dammed river runs wild again and three scrap-clans are bleeding over the spillage. The [[Ouiye Aundii|ouiye-aundii]] keep to the deep gullies the windstorms guard, and they keep something else besides — heirlooms they cannot read.', 'The windstorms are not random. They thicken over the places where the rock is thinnest, as if the land were breathing through its wounds — and the worst of them blow up from below, not across.', 'The storms intensify near the buried Monastery; the land''s stabilising machinery is failing, venting pressure.', '5 published micro-locations. Monastery left undiscovered as the deep secret.', NULL, 'micro', 'quadrant', 0, 0, NULL, NULL, 'moderate', 'scarce', ARRAY['sector','frontier','arid']::text[], true, 610, 430, 150, 'dust-gullets', 'charted', NULL),
  ('e45399ca-8e9b-5ee8-8ec8-80e840af15a8', 'sector', 'The Pale Reach', '22766cd4-f472-5320-8da0-e29699596b4b', 'North-west of the Gullets the land goes pale and flat. Sand the colour of old bone. There''s water under the cactus, they say, if the things in the sand don''t reach you first.', 'Flat, open, bleached dunes — amber deepening to near-white. The cactus Spires mark deep groundwater. The oases are the only reason to come: the [[Amber Well|amber-well]] and the [[Gilded Mirage|gilded-mirage]]. The [[Bleached Crossing|bleached-crossing]] is a known killing ground. A single [[Karrath pack|karrath-pack]] hunts the Reach now.', 'The [[Amber Well|amber-well]]''s water-council rations by an old debt-ledger and will let a stranger die of thirst over a technicality. The [[Gilded Mirage|gilded-mirage]] runs by two rules — have fun, keep it clean — and the [[Jewel|the-jewel]] enforces the second with more violence than the first. The Karrath avoid the Mirage; they disdain to walk among the weak.', 'The corruption-pulse that drew the Karrath north did not come from the surface. Something is turning beneath the [[Bleached Crossing|bleached-crossing]], in the dry bones of the old river. The pack knows. They are not hunting in the Reach — they are waiting on it.', 'The pulse originates from the same failing stabiliser as the Gullets storms; the dry river-bed connects to the buried system.', '5 published micro-locations; vessel starts at 2 discovered = 40% (matches plan example).', NULL, 'micro', 'quadrant', 0, 0, NULL, NULL, 'low', 'scarce', ARRAY['sector','desert','oases']::text[], true, 320, 250, 140, 'pale-reach', 'charted', NULL),
  ('ca5ff00d-8b1b-56e8-88b3-eb92a391a6df', 'sector', 'Q2 · Sector 3', '22766cd4-f472-5320-8da0-e29699596b4b', '', 'Open country. Untold.', '', '', '', 'Placeholder — GM to author.', NULL, 'micro', 'quadrant', 0, 0, NULL, NULL, NULL, NULL, ARRAY['sector','placeholder']::text[], true, 180, 470, 90, 'q2-s3', 'uncharted', NULL),
  ('3a945e95-cee4-5c08-84b6-2a58279158bf', 'sector', 'Q2 · Sector 4', '22766cd4-f472-5320-8da0-e29699596b4b', '', 'Open country. Untold.', '', '', '', 'Placeholder.', NULL, 'micro', 'quadrant', 0, 0, NULL, NULL, NULL, NULL, ARRAY['sector','placeholder']::text[], true, 470, 200, 85, 'q2-s4', 'uncharted', NULL),
  ('40ba1609-7379-54ec-8af7-2d74d233ff87', 'sector', 'Q2 · Sector 5', '22766cd4-f472-5320-8da0-e29699596b4b', '', 'Open country. Untold.', '', '', '', 'Placeholder.', NULL, 'micro', 'quadrant', 0, 0, NULL, NULL, NULL, NULL, ARRAY['sector','placeholder']::text[], true, 150, 220, 90, 'q2-s5', 'uncharted', NULL),
  ('18dd1c2d-956a-5647-8bcf-63da0e966aa4', 'sector', 'Q2 · Sector 6', '22766cd4-f472-5320-8da0-e29699596b4b', '', 'Open country. Untold.', '', '', '', 'Placeholder.', NULL, 'micro', 'quadrant', 0, 0, NULL, NULL, NULL, NULL, ARRAY['sector','placeholder']::text[], true, 820, 250, 85, 'q2-s6', 'uncharted', NULL),
  ('95bf82ac-c918-5682-8d75-14607f1ef3ed', 'sector', 'Q2 · Sector 7', '22766cd4-f472-5320-8da0-e29699596b4b', '', 'Open country. Untold.', '', '', '', 'Placeholder.', NULL, 'micro', 'quadrant', 0, 0, NULL, NULL, NULL, NULL, ARRAY['sector','placeholder']::text[], true, 840, 470, 90, 'q2-s7', 'uncharted', NULL),
  ('8a131227-c0d7-5e66-8dff-21c2ac24d7da', 'sector', 'Q2 · Sector 8', '22766cd4-f472-5320-8da0-e29699596b4b', '', 'Open country. Untold.', '', '', '', 'Placeholder.', NULL, 'micro', 'quadrant', 0, 0, NULL, NULL, NULL, NULL, ARRAY['sector','placeholder']::text[], true, 430, 560, 95, 'q2-s8', 'uncharted', NULL),
  ('95db3752-4fcc-5157-886c-43297de59d88', 'sector', 'Q2 · Sector 9', '22766cd4-f472-5320-8da0-e29699596b4b', '', 'Open country. Untold.', '', '', '', 'Placeholder.', NULL, 'micro', 'quadrant', 0, 0, NULL, NULL, NULL, NULL, ARRAY['sector','placeholder']::text[], true, 680, 580, 90, 'q2-s9', 'uncharted', NULL),
  ('4d067d6c-95a1-5070-862c-19b1cb9ff1e1', 'location', 'The High Aerie', 'c619c671-3d99-5bf6-839c-a7c3d72a24ed', 'The Blue Leaf''s eyrie, up in the cliff-marrow. They said it could never fall. They were wrong.', 'The [[Blue Leaf Rancho|blue-leaf-rancho]]''s cliff-fortress, raised atop a massive face over the dammed Fluid Vein and long thought impenetrable. Now collapsed — a rubble field with a waterfall pouring through where a tyranny used to sit.', 'The collapse freed the dammed river. Scrap-clans now fight over the spill, and the ruin is picked-over but not emptied — the deepest vaults went down with the cliff and no one has reached them.', 'The fall was not a siege and not an accident. The cliff failed from inside, along a seam no surveyor had mapped — as though the rock itself let go.', 'The seam follows a buried conduit of the Monastery system. The Aerie was built, unknowingly, on top of failing ancient machinery.', 'Sector-shaping event. Ripples ongoing.', 'collapsed_site', 'macro', 'sector', 640, 300, NULL, NULL, NULL, NULL, ARRAY['location:dust-gullets','faction:blue-leaf']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('e2f4d03c-cd52-5e62-890a-fce9a7e0416f', 'location', 'The Fluid Vein', 'c619c671-3d99-5bf6-839c-a7c3d72a24ed', 'There''s a river under the Gullets, they say. The Blue Leaf put a wall across it and got rich.', 'The sector''s only significant water — a vast underground river dammed inside the cliff-marrow and routed up into the [[High Aerie|high-aerie]]. The dam is breached now and the water runs where it likes.', 'Where the freed water meets old scrap-tailings it turns the colour of rust and is unsafe to drink for a day''s walk downstream.', '', '', '', 'underground_river', 'micro', 'sector', 560, 420, NULL, NULL, NULL, NULL, ARRAY['location:dust-gullets','water']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('72d6e1a9-ef0c-5e97-81e1-dda8be56479e', 'location', 'The Scrap Warren', 'c619c671-3d99-5bf6-839c-a7c3d72a24ed', 'Men go into the holes for iron and copper. Not all of them come back, and not all that come back are still men.', 'A maze of scrap-mines bored into the iron-rich rock. Profitable and lethal in equal measure — dig in the wrong direction and you breach a Corruption Vein.', '', '', '', '', 'mine', 'micro', 'sector', 740, 380, NULL, NULL, NULL, NULL, ARRAY['location:dust-gullets','scrap']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('4cec41c3-7dad-527a-816b-020492d0ba6c', 'location', 'The Weeping Breach', 'c619c671-3d99-5bf6-839c-a7c3d72a24ed', 'There''s a hole in the rock that breathes wrong. Nobody mines near it twice.', 'A breached Corruption Vein — a wound in the rock where compressed reality-trauma leaks into the air. Exposure dissolves the self; long exposure makes a Swallowed One.', '', '', '', '', 'vein_breach', 'micro', 'sector', 690, 500, NULL, NULL, NULL, NULL, ARRAY['location:dust-gullets','corruption']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('41c649a7-04f3-57fd-844c-cb8a7c4fdfd3', 'location', 'The Monastery of the Archon of Earth', 'c619c671-3d99-5bf6-839c-a7c3d72a24ed', 'An old, old story among the [[Ouiye Aundii|ouiye-aundii]] — a holy place under the sand that could mend the world, if anyone remembered how.', 'A pre-cataclysm facility of the Archon of Earth — Forge and Structure — buried beneath the Gullets. Said to be activatable with the right keys.', 'Activated, it would process the land''s corruption and lock reality back into place for hundreds of miles — a permanent sanctuary. The full requirements are not understood.', 'The Ouiye Aundii are the descendants of its keepers, though they have forgotten what they keep. The Earth-Chord Cylinder is one key. There are others. No one living knows how many.', 'Its slow failure is the source of the sector''s storms and the Reach''s corruption-pulse. Reactivation is a campaign-scale goal.', 'Deliberately UNDISCOVERED at start — the buried secret of Q2.', 'buried_facility', 'macro', 'sector', 500, 360, NULL, NULL, NULL, NULL, ARRAY['location:dust-gullets','holy','secret']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('3cdaff70-cb98-5739-8d35-1f655c6a42a2', 'location', 'The Amber Well', 'e45399ca-8e9b-5ee8-8ec8-80e840af15a8', 'A walled oasis run by a council that would rather watch you die of thirst than break their own ledger.', 'A walled oasis settlement built around deep groundwater, ruled by a small water-council. Insular and watchful, dangerous in a social rather than a violent way.', 'The council rations by an old debt-ledger and will let a stranger die over a technicality. They hold the Ledger of Thirsts — a book recording every water-debt in the sector, and a political weapon.', 'The [[Jewel|the-jewel]] of the Mirage was raised here, on the council''s water-debt ledgers, and left when they understood what they had made.', '', '', 'walled_oasis', 'macro', 'sector', 360, 300, NULL, NULL, NULL, NULL, ARRAY['location:pale-reach','water','faction-seat']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('b509dcaf-8e1c-5250-8b08-34891b4a89c5', 'location', 'The Gilded Mirage', 'e45399ca-8e9b-5ee8-8ec8-80e840af15a8', 'An oasis town with two rules — have fun, keep it clean — and a ruler called the [[Jewel|the-jewel]] who kills faster over the second than the first.', 'A loud, alive, lawless-but-clean oasis town: a hub of trade, information, outlaws, and stranger commerce. A refuge from the [[Karrath|karrath-pack]], who disdain to walk among the weak — and a den of every other danger.', 'Information flows through the [[Jewel|the-jewel]] the way water flows through the [[Amber Well|amber-well]] — controlled, rationed, and sold.', '', '', '', 'oasis_town', 'macro', 'sector', 250, 210, NULL, NULL, NULL, NULL, ARRAY['location:pale-reach','faction:gilded-mirage']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('04351ebe-07b9-5c9b-8aec-8e5c185a203a', 'location', 'The Bleached Crossing', 'e45399ca-8e9b-5ee8-8ec8-80e840af15a8', 'A dry river full of bones. They say the sand swims there.', 'A dry river-bed strewn with bones — a known killing ground of sand-swimming predators.', '', 'Something is turning beneath it, in the bones of the old river. The corruption-pulse that drew the Karrath north rises from here.', 'Connects to the buried Monastery system.', '', 'bone_field', 'micro', 'sector', 520, 430, NULL, NULL, NULL, NULL, ARRAY['location:pale-reach','danger']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('87c09168-d43b-56ca-8fa0-5ead4b04e9c5', 'location', 'The Tall Spires', 'e45399ca-8e9b-5ee8-8ec8-80e840af15a8', 'Old cactus the size of towers. Where they grow, there''s water deep down.', 'A grove of ancient cactus Spires marking deep groundwater — a landmark and a lifeline for those who know to read them.', '', '', '', '', 'spire_grove', 'micro', 'sector', 180, 400, NULL, NULL, NULL, NULL, ARRAY['location:pale-reach','water']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('7f920704-ac82-598a-8468-ea7c684126de', 'location', 'The Pack''s Hunting Ground', 'e45399ca-8e9b-5ee8-8ec8-80e840af15a8', 'Six of them, they say. Never more, never fewer. They hunt the open Reach now.', 'The roaming territory of a single [[Karrath pack|karrath-pack]] — six predators drawn north by a corruption-pulse.', '', '', '', '', 'karrath_ground', 'macro', 'sector', 640, 260, NULL, NULL, NULL, NULL, ARRAY['location:pale-reach','faction:karrath','danger']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('0a3264f3-1b0e-51be-83b6-2e7461f21455', 'people', 'The Jewel of the Gilded Mirage', NULL, 'They say the Mirage has a ruler called the Jewel. Two rules in that town — have fun, keep it clean — and the Jewel kills faster over the second than the first.', 'The sovereign of the [[Gilded Mirage|gilded-mirage]]. Keeps order through generosity and sudden, precise violence. Information flows through the Jewel the way water flows through the [[Amber Well|amber-well]] — controlled, rationed, and sold.', 'Few favours the Jewel grants are free, and none are forgotten. The Mirage''s cleanliness is not vanity — it is the one law the Jewel will kill over without warning.', 'The Jewel is not selling escape because they fear the corruption-pulse. They are selling it because they intend to be the last one holding anything of value when the Reach turns — and have already decided who is worth taking and who is being left.', 'The Jewel has a private cache and an escape route west. Knows more about the pulse than they admit.', 'People entity → UI shows ''Met'' instead of ''Visited''.', NULL, 'micro', 'none', 0, 0, NULL, NULL, NULL, NULL, ARRAY['faction:gilded-mirage','location:gilded-mirage']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('be6f057c-1d72-5259-803b-fd820630b3ec', 'faction', 'The Blue Leaf Rancho', NULL, 'The water-tyrants of the Gullets. Owned the river, so they owned everyone.', 'A resource-empire that ruled the [[Dust Gullets|dust-gullets]] through a monopoly on the sector''s only water, from the cliff-fortress called the [[High Aerie|high-aerie]]. Now broken with the Aerie''s fall.', 'Like all Ranchos it was ruled by a shrouded Master beneath fanatically devoted Commanders. With the Master''s seat collapsed, those Commanders are scattered and dangerous.', '', '', '', NULL, 'micro', 'none', 0, 0, NULL, NULL, NULL, NULL, ARRAY['location:dust-gullets']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('605a7bce-f201-5eb5-88b8-4d0f78de515d', 'faction', 'The Ouiye Aundii', NULL, 'An old tribe of the Gullets. They keep to the deep gullies and keep old things they won''t explain.', 'A tribe of the [[Dust Gullets|dust-gullets]], bound to land and lineage and the Archons. Earth-marked in the main — they speak in structures and orders, lists and proper sequences.', 'They keep ancestral heirlooms whose true purpose they no longer understand. Their ancestors were once keepers of something beneath the sand.', 'They are the descendants of the keepers of the [[Monastery of the Archon of Earth|ouiye-monastery]].', '', '', NULL, 'micro', 'none', 0, 0, NULL, NULL, NULL, NULL, ARRAY['location:dust-gullets','tribe','archon:earth']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('b5d8455d-05f3-539f-8092-2164c02ce844', 'people', 'The Karrath Pack of the Reach', NULL, 'Six predators that hunt as one. They worship the Blood Moon and they take the wrong-blooded.', 'A pack of exactly six Karrath — Alpha, Seer, Betas, Hunters — drawn into the [[Pale Reach|pale-reach]] by a corruption-pulse. They cleanse corruption by offering wrong-blood to the Blood Moon.', 'They disdain to hunt among the weak, which is why the [[Gilded Mirage|gilded-mirage]] is safe from them. A successful offering turns the sacrificer''s skin permanently red — the right to lead and to sire the next generation.', 'They are not hunting the Reach. They are waiting on whatever is turning beneath the [[Bleached Crossing|bleached-crossing]].', '', '', NULL, 'micro', 'none', 0, 0, NULL, NULL, NULL, NULL, ARRAY['faction:karrath','location:pale-reach','archon:moon']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('4d9fbcf6-9ddb-52f1-8bba-dd5a4d958e48', 'faction', 'The Archonic Church', NULL, 'The faith of the eight faceless Archons. They hold the Road, or try to.', 'The dominant faith of the Fracta — eight faceless Archons who speak only in symbolic vision, never words. Every being is Marked by one at birth. The Church is the closest thing the broken world has to order, and it guards the [[Ancient Holy Road|ancient-holy-road]].', '', '', '', '', NULL, 'micro', 'none', 0, 0, NULL, NULL, NULL, NULL, ARRAY['religion']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('a3b3f0f5-9bbd-59f5-8db6-969e8e95d135', 'role', 'The Witness', NULL, 'One who carries the world''s corruption so others need not.', 'A role, not a person: the bearer of the Staff of Corruption, a spiritual filter that draws ambient corruption away from allies and forces it into the bearer''s own mind — sanity spent to keep the world from dissolving.', '', '', '', '', NULL, 'micro', 'none', 0, 0, NULL, NULL, NULL, NULL, ARRAY['role']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('60612ad0-6f0c-57d1-8fc8-7bbdb1664221', 'corridor', 'The Ancient Holy Road', '27fbc1d3-fb98-56e1-8d30-7253c15f9934', 'The old road. Runs from the top of the world all the way down to the Wall. They say you can cross the whole Fracta on it in a month, if the road lets you. Mostly it doesn''t. Faster than going around — that''s how it gets you.', 'Runs the length of the continent, from the northern quadrant down to the Wall of the SoA. Older than the present age, built on a scale no one can match now — arcs ten to fifteen metres tall, ruined aqueducts, towers, structures large enough to shelter towns. The [[Archonic Church|archonic-church]] holds stretches and tries to keep it passable, but the road is long — a month of wagon travel — and they cannot hold all of it. The unheld stretches belong to lawless men and worse.', 'The held stretches are marked by gate-towns and protected camps; the unheld stretches by ambush and silence. Travellers learn to read which is which before nightfall.', 'Where the Echo runs strong, the road remembers itself — processions that are not there, lights in fallen towers, the sound of many feet walking south in the dark.', 'The Road''s true purpose, what walks it, and how it connects to the Wall and to Delirium — author to campaign. One of the world''s central secrets.', 'Corridor entity. Children are waypoints with sequence_index. Drawn as overlay ribbon on the continent map.', NULL, 'micro', 'continent', 0, 0, NULL, NULL, NULL, NULL, ARRAY['corridor','holy','contested']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('ba1dfa18-3605-513e-810e-a04dae42721d', 'waypoint', 'The Northern Threshold', '60612ad0-6f0c-57d1-8fc8-7bbdb1664221', 'Where the Road begins, at the top of the world.', 'A gate-town at the Road''s northern origin in Q1, held by the Church. The last reliably safe stop before the long descent.', '', '', '', '', 'gate_town', 'micro', 'corridor', 0, 0, 1, NULL, NULL, NULL, ARRAY['corridor']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('a34f9228-ee33-5542-8641-4c755f9826be', 'waypoint', 'The Sundered Aqueduct', '60612ad0-6f0c-57d1-8fc8-7bbdb1664221', 'A broken water-arch big enough to march an army under.', 'A ruined aqueduct spanning the road where it forms the border of Q3 and Q4 — a landmark, a shelter, and an ambush point all at once.', '', '', '', '', 'aqueduct', 'micro', 'corridor', 0, 0, 2, NULL, NULL, NULL, ARRAY['corridor']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('d7a8747e-23b9-5be0-8b8c-e6ef7c351752', 'waypoint', 'The Watching Towers', '60612ad0-6f0c-57d1-8fc8-7bbdb1664221', 'Towers that still have lights in them, some nights, with no one inside.', 'A line of ancient towers along the Q6 stretch — half-held by the Church, half-haunted by the Echo.', '', '', '', '', 'tower', 'micro', 'corridor', 0, 0, 3, NULL, NULL, NULL, ARRAY['corridor','echo']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('f3aac5b6-4003-5213-8122-6e532805782e', 'waypoint', 'The Wall Approach', '60612ad0-6f0c-57d1-8fc8-7bbdb1664221', 'The end of the Road. The Wall. Few who set out for it arrive.', 'The Road''s terminus at the Wall of the SoA — the broken defensive line with its gap-towns, and the holiest place in the world beyond.', '', '', 'The true nature of the SoA is a central secret.', '', 'wall_sanctum', 'micro', 'corridor', 0, 0, 4, NULL, NULL, NULL, ARRAY['corridor','holy']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('07e0856e-8978-5d6a-82be-b821a10cb5df', 'item', 'The Earth-Chord Cylinder', NULL, 'An old stone rod the tribes won''t sell. Lines on it that move when you aren''t looking.', 'A hand-length cylinder of dense dark stone inscribed with shifting geometric lines — a coded key to the [[Monastery of the Archon of Earth|ouiye-monastery]], kept as an heirloom by tribes who have forgotten what it is.', '', 'It is one key of several. No one living knows how many it takes.', '', '', NULL, 'micro', 'none', 0, 0, NULL, NULL, NULL, NULL, ARRAY['item','archon:earth','key']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL),
  ('a2ba2ec7-34e7-55c6-8588-17793c550e89', 'item', 'The Staff of Corruption', NULL, 'The Witness''s staff. It eats the rot of the world and feeds it to the one who holds it.', 'The [[Witness|the-witness]]''s tool — a spiritual filter that draws ambient corruption away from allies and forces it into the bearer''s mind, preventing the world dissolving around them at the cost of their sanity.', 'Ancient, having survived many ages. Can serve as an anchor for a tethered spirit, dependent on a living bearer.', '', '', '', NULL, 'micro', 'none', 0, 0, NULL, NULL, NULL, NULL, ARRAY['item','anchor']::text[], true, NULL, NULL, NULL, NULL, NULL, NULL)
INSERT INTO public.deep_lore_entries
  (id, entity_id, origin_faction, origin_entity_id, lore_text, access_note, sort_order, is_published)
VALUES
  ('062e1903-5421-52cb-8e3f-3e851db4573c', 'c619c671-3d99-5bf6-839c-a7c3d72a24ed', 'Tradition of the Ouiye Aundii', '605a7bce-f201-5eb5-88b8-4d0f78de515d', 'Beneath the Gullets lies the Monastery of the Archon of Earth — a pre-cataclysm facility built by hands that served Forge and Structure before the Dissolution. The Ouiye Aundii are the descendants of its keepers, though they have forgotten what they keep. Activated with the right keys, it would process the land''s corruption and lock reality back into place for hundreds of miles. The Earth-Chord Cylinder is one key. There are others. No one living knows how many.', 'Requires the trust of the Ouiye Aundii.', 1, true),
  ('d873c932-e3f2-599d-884b-4bf0ac93f63c', '0a3264f3-1b0e-51be-83b6-2e7461f21455', 'The Amber Well water-council', '3cdaff70-cb98-5739-8d35-1f655c6a42a2', 'The council will tell you, for a price, that the Jewel once belonged to the Well — raised on its water-debt ledgers, and left when they understood that a town with no walls and one rule about cleanliness could be controlled more completely than a town with a hundred laws. They call the Jewel their most successful graduate, the way you describe a wound that healed wrong.', 'Bought, for a price, from the Amber Well council.', 1, true),
  ('cca2ff89-baf6-585b-8442-700fce99088a', '60612ad0-6f0c-57d1-8fc8-7bbdb1664221', 'The Echo / direct experience', NULL, 'The Road was not built for travel. Its scale and its alignment toward the Wall were built to mean something, in an age when the Fracta could build meaning into stone. What it was for is forgotten, but the stone has not forgotten. Where the Echo runs strong, travellers report the road remembering itself: processions that are not there, lights in fallen towers, the sound of a great many feet walking south in the dark. The religious forces do not protect the Road only from bandits. They protect it from what it still is.', 'Earned by those who have walked the haunted stretches and lived.', 1, true),
  ('e74cb51c-41a6-53b3-86fe-bd8ec7dbb450', '60612ad0-6f0c-57d1-8fc8-7bbdb1664221', 'The Karrath', 'b5d8455d-05f3-539f-8092-2164c02ce844', 'The Road is a scar. Wrong-blood ran here in a quantity the Moon still remembers, and the stone drank it and will not let it go. The faithful walk it south as if it were holy. It is not holy. It is a throat, and it is still swallowing.', 'Spoken in clicks and throat-calls, to those the pack does not eat.', 2, true),
  ('beca2ebb-de5f-5cc1-840a-7a7918a11395', '60612ad0-6f0c-57d1-8fc8-7bbdb1664221', 'The Archonic Church', '4d9fbcf6-9ddb-52f1-8bba-dd5a4d958e48', 'The Road was laid by the first faithful, that the pilgrim might walk unbroken from the top of the world to the Wall of the SoA and stand at the threshold of the Archons. That it has fallen to ruin and to lawless men is the age''s great shame, and to keep even one stretch of it passable is an act of devotion. Walk it south. The Archons are at the end of it.', 'Doctrine, granted to the devout.', 3, true)
